import json
import pandas as pd
import re

# Load clinical data
clinical_file = var_functions.query_db:62
if isinstance(clinical_file, str) and clinical_file.endswith('.json'):
    with open(clinical_file, 'r') as f:
        clinical_list = json.load(f)
else:
    clinical_list = clinical_file

# Count histological types
histology_counts = {}
for rec in clinical_list:
    hist = rec.get('histological_type')
    if hist:
        histology_counts[hist] = histology_counts.get(hist, 0) + 1

print('Histology distribution:')
for hist, count in sorted(histology_counts.items(), key=lambda x: x[1], reverse=True):
    print(f'  {hist}: {count}')

# Check if any category has > 10
larger_categories = {h: c for h, c in histology_counts.items() if c > 10}
print('\nCategories with >10 patients:', len(larger_categories))

result = {
    'total_histologies': len(histology_counts),
    'categories_over_10': len(larger_categories),
    'distribution': histology_counts
}

print('__RESULT__:')
print(json.dumps(result))

